import { forbidden } from 'next/navigation'

import { verifyAdmin } from '@/app/lib/auth'

export default async function AdminPage() {
  const { isAdmin, session } = await verifyAdmin()

  if (!isAdmin || !session) {
    forbidden()
  }

  return (
    <main style={{ maxWidth: 960, margin: '0 auto', padding: '64px 24px' }}>
      <p style={{ color: '#64748b', fontSize: 14, margin: 0 }}>Administration</p>
      <h1 style={{ color: '#0f172a', fontSize: 40, margin: '8px 0 12px' }}>
        Admin Dashboard
      </h1>
      <p style={{ color: '#475569', fontSize: 18, margin: 0 }}>
        Welcome, {session.name}. You have access to administrative tools.
      </p>
    </main>
  )
}

